const raw = $input.first().json;
let time = '', message = 'Reminder!', type = 'reminder', action = '';
try {
  const p = JSON.parse(raw.query || '{}');
  time = p.time || '';
  message = p.message || 'Reminder!';
  type = p.type || 'reminder';
  action = p.action || '';
  // Pass through all parsed fields for recurring/management
  var params = p;
} catch(e) {
  time = raw.time || '';
  message = raw.message || 'Reminder!';
  type = raw.type || 'reminder';
  action = raw.action || '';
  var params = raw;
}

const chatId = raw.chatId || raw.chat_id || '{{TELEGRAM_CHAT_ID}}';
const userId = raw.userId || raw.user_id || 'telegram:{{TELEGRAM_CHAT_ID}}';
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';

// ── Management actions for scheduled_actions ──
if (action === 'list') {
  const actions = await helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/scheduled_actions?user_id=eq.${encodeURIComponent(userId)}&order=created_at.desc`,
    headers: { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' },
    json: true
  });
  if (!actions || actions.length === 0) {
    return [{ json: { success: true, message: 'No scheduled actions found.' } }];
  }
  const lines = actions.map(a => {
    const status = a.enabled ? 'active' : 'disabled';
    const sched = a.schedule;
    let schedStr = '';
    if (sched.type === 'interval') schedStr = `every ${sched.minutes} min`;
    else if (sched.type === 'daily') schedStr = `daily at ${sched.time}`;
    else if (sched.type === 'weekly') schedStr = `weekly (days: ${sched.days.join(',')}) at ${sched.time}`;
    const mode = a.notify_mode === 'on_change' ? '🔇' : '🔔';
    return `[${a.id}] ${mode} ${a.name} (${schedStr}) - ${status} - runs: ${a.run_count}`;
  });
  return [{ json: { success: true, message: lines.join('\n') } }];
}

if (action === 'enable' || action === 'disable') {
  const targetId = params.target_id;
  if (!targetId) return [{ json: { success: false, message: 'target_id is required' } }];
  const enabled = action === 'enable';
  // If re-enabling, recompute next_run
  let body = { enabled, updated_at: new Date().toISOString() };
  if (enabled) {
    // Fetch the action to get its schedule
    const acts = await helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/scheduled_actions?id=eq.${targetId}&select=schedule,timezone`,
      headers: { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' },
      json: true
    });
    if (acts && acts.length > 0) {
      // Set next_run to now so it fires on the next heartbeat cycle
      body.next_run = new Date().toISOString();
    }
  }
  await helpers.httpRequest({
    method: 'PATCH',
    url: `${SUPABASE_URL}/rest/v1/scheduled_actions?id=eq.${targetId}`,
    headers: { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
    body,
    json: true
  });
  return [{ json: { success: true, message: `Scheduled action ${targetId} ${action}d.` } }];
}

if (action === 'delete') {
  const targetId = params.target_id;
  if (!targetId) return [{ json: { success: false, message: 'target_id is required' } }];
  await helpers.httpRequest({
    method: 'DELETE',
    url: `${SUPABASE_URL}/rest/v1/scheduled_actions?id=eq.${targetId}`,
    headers: { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
    json: true
  });
  return [{ json: { success: true, message: `Scheduled action ${targetId} deleted.` } }];
}

// ── Recurring: create scheduled action ──
if (type === 'recurring') {
  const schedule = params.schedule || { type: 'interval', minutes: 60 };
  const name = params.name || message;
  const instruction = params.instruction || message;
  const actionType = params.action_type || 'agent_task';
  const notifyMode = params.notify_mode || 'always';
  const tz = params.timezone || 'Europe/Berlin';

  // Compute initial next_run
  const now = new Date();
  let nextRun;
  if (schedule.type === 'interval') {
    nextRun = new Date(now.getTime() + (schedule.minutes || 60) * 60000 - 30000).toISOString();
  } else if (schedule.type === 'daily') {
    const [h, m] = (schedule.time || '08:00').split(':').map(Number);
    const userNow = new Date(now.toLocaleString('en-US', { timeZone: tz }));
    const target = new Date(userNow);
    target.setHours(h, m, 0, 0);
    if (target <= userNow) target.setDate(target.getDate() + 1);
    const diffMs = target.getTime() - userNow.getTime();
    nextRun = new Date(now.getTime() + diffMs).toISOString();
  } else if (schedule.type === 'weekly') {
    const [h, m] = (schedule.time || '09:00').split(':').map(Number);
    const days = schedule.days || [1];
    const userNow = new Date(now.toLocaleString('en-US', { timeZone: tz }));
    const jsDay = userNow.getDay();
    const currentDay = jsDay === 0 ? 7 : jsDay;
    const currentMinutes = userNow.getHours() * 60 + userNow.getMinutes();
    const targetMinutes = h * 60 + m;
    let minDaysAhead = 8;
    for (const d of days) {
      let ahead = d - currentDay;
      if (ahead < 0) ahead += 7;
      if (ahead === 0 && currentMinutes >= targetMinutes) ahead = 7;
      if (ahead < minDaysAhead) minDaysAhead = ahead;
    }
    const target = new Date(userNow);
    target.setDate(target.getDate() + minDaysAhead);
    target.setHours(h, m, 0, 0);
    const diffMs = target.getTime() - userNow.getTime();
    nextRun = new Date(now.getTime() + diffMs).toISOString();
  } else {
    nextRun = new Date(now.getTime() + 3600000).toISOString();
  }

  const response = await helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/scheduled_actions`,
    headers: {
      'Content-Type': 'application/json',
      'apikey': SUPABASE_KEY,
      'Prefer': 'return=representation'
    },
    body: {
      user_id: userId,
      chat_id: String(chatId),
      name,
      action_type: actionType,
      instruction,
      schedule,
      timezone: tz,
      next_run: nextRun,
      notify_mode: notifyMode,
      enabled: true
    },
    json: true
  });

  let schedStr = '';
  if (schedule.type === 'interval') schedStr = `every ${schedule.minutes} minutes`;
  else if (schedule.type === 'daily') schedStr = `daily at ${schedule.time}`;
  else if (schedule.type === 'weekly') schedStr = `weekly on days ${schedule.days.join(',')} at ${schedule.time}`;

  return [{ json: { success: true, message: `Recurring action "${name}" created (${schedStr}). Next run: ${nextRun}`, id: response[0]?.id } }];
}

// ── Original: reminder or task ──
const remindAt = time || new Date().toISOString();

const response = await helpers.httpRequest({
  method: 'POST',
  url: `${SUPABASE_URL}/rest/v1/reminders`,
  headers: {
    'Content-Type': 'application/json',
    'apikey': SUPABASE_KEY,
    'Prefer': 'return=representation'
  },
  body: {
    user_id: userId,
    chat_id: String(chatId),
    message: message,
    remind_at: remindAt,
    type: type
  },
  json: true
});

const label = type === 'task' ? 'Scheduled task' : 'Reminder';
return [{ json: { success: true, message: `${label} set for ${remindAt}: ${message}`, id: response[0]?.id } }];
